const row = $json;
const v = [Number(row.v1), Number(row.v2), Number(row.v3), Number(row.v4)];
const uid = String(row.user_id || 'demo-user');
const searchBody = {
  vector: v,
  limit: 6,
  with_payload: true,
  with_vector: false,
  filter: {
    must: [{ key: 'user_id', match: { value: uid } }],
  },
};
return [{ json: { ...row, searchBodyString: JSON.stringify(searchBody) } }];

const norm = $items('Normalize Input', 0, 0)[0].json;
const raw = $json.result;
const hits = Array.isArray(raw) ? raw : [];
const lines = [];
for (const h of hits) {
  const p = h.payload || {};
  const a = p.assistant_reply ? String(p.assistant_reply).slice(0, 240) : '';
  const m = p.message ? String(p.message).slice(0, 240) : '';
  if (m || a) lines.push('- Пользователь: ' + m + (a ? (' | Ассистент: ' + a) : ''));
}
const memBlock = lines.length ? ('Контекст из памяти (прошлые реплики этого user_id):\n' + lines.join('\n')) : '';
const sys = 'Ты полезный короткий ассистент SonBot. Отвечай на русском, конкретно. Если дали блок памяти — учитывай факты из него, не выдумывай лишнего.\n\n' + memBlock;
const llmBody = {
  model: 'gpt-4o-mini',
  temperature: 0.4,
  messages: [
    { role: 'system', content: sys },
    { role: 'user', content: String(norm.message || '') },
  ],
};
return [{
  json: {
    user_id: norm.user_id,
    message: norm.message,
    point_id: norm.point_id,
    v1: norm.v1,
    v2: norm.v2,
    v3: norm.v3,
    v4: norm.v4,
    request_started_ms: norm.request_started_ms,
    llmBodyString: JSON.stringify(llmBody),
    used_memory_count: hits.length,
  },
}];

const llm = $json;
const carry = $items('Build LLM Body', 0, 0)[0].json;
const content = llm?.choices?.[0]?.message?.content || (typeof llm?.error?.message === 'string' ? llm.error.message : '') || 'Извини, не удалось получить ответ от модели.';
const upsertBody = {
  points: [
    {
      id: Number(carry.point_id),
      vector: [Number(carry.v1), Number(carry.v2), Number(carry.v3), Number(carry.v4)],
      payload: {
        user_id: carry.user_id,
        message: carry.message,
        assistant_reply: content,
        created_at: new Date().toISOString(),
      },
    },
  ],
};
return [{
  json: {
    user_id: carry.user_id,
    message: carry.message,
    point_id: carry.point_id,
    v1: carry.v1,
    v2: carry.v2,
    v3: carry.v3,
    v4: carry.v4,
    request_started_ms: carry.request_started_ms,
    used_memory_count: carry.used_memory_count,
    assistant_reply: content,
    llm_model: llm?.model || null,
    upsertBodyString: JSON.stringify(upsertBody),
  },
}];

const q = $json;
const carry = $items('Build Upsert After LLM', 0, 0)[0].json;
const t0 = Number(carry.request_started_ms) || Date.now();
const upsertOk = q.status === 'ok';
return [{
  json: {
    status: 'ok',
    user_id: carry.user_id,
    input_message: carry.message,
    assistant_reply: carry.assistant_reply,
    model: carry.llm_model || 'gpt-4o-mini',
    used_memory_count: carry.used_memory_count,
    latency_ms: Date.now() - t0,
    memory_upsert_ok: upsertOk,
  },
}];
